# Module defining interfaces and abstract base class for shapes
interface IDrawable:
    @abstract
    def draw(self) -> str: ...

interface IMeasurable:
    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

@abstract
class Shape:
    _name: str

    def __init__(self, name: str):
        self._name = name

    @virtual
    def get_name(self) -> str:
        return self._name

    @abstract
    def describe(self) -> str: ...

